import React, { useState, useEffect, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
import api from '../utils/api';

interface BotForm {
  keywords: string;
  location: string;
  limit: number;
  autoSend: boolean;
}

interface LogEntry {
  type: string;
  message: string;
  step?: string;
  ts: string;
}

interface BotStatus {
  waiting: number;
  active: number;
  completed: number;
  failed: number;
  lastJob?: any;
}

const LOG_COLORS: Record<string, string> = {
  log: 'text-zinc-400',
  lead: 'text-emerald-400',
  done: 'text-indigo-400 font-semibold',
  error: 'text-red-400',
  warn: 'text-amber-400',
};

const LOG_PREFIX: Record<string, string> = {
  log: 'INFO',
  lead: 'LEAD',
  done: 'DONE',
  error: 'ERR ',
  warn: 'WARN',
};

function PlayIcon(): React.ReactElement {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
      <polygon points="5 3 19 12 5 21 5 3" />
    </svg>
  );
}

function StopIcon(): React.ReactElement {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
      <rect x="3" y="3" width="18" height="18" rx="2" />
    </svg>
  );
}

function ClearIcon(): React.ReactElement {
  return (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="3 6 5 6 21 6" />
      <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6" />
      <path d="M10 11v6M14 11v6" />
    </svg>
  );
}

interface ToggleProps {
  checked: boolean;
  onChange: (v: boolean) => void;
  label: string;
  description?: string;
}

function Toggle({ checked, onChange, label, description }: ToggleProps): React.ReactElement {
  return (
    <div className="flex items-start justify-between gap-4">
      <div>
        <p className="text-xs font-medium text-zinc-200">{label}</p>
        {description && <p className="text-xs text-zinc-600 mt-0.5">{description}</p>}
      </div>
      <button
        type="button"
        onClick={() => onChange(!checked)}
        className={`relative flex-shrink-0 w-9 h-5 rounded-full transition-colors ${
          checked ? 'bg-indigo-600' : 'bg-zinc-700'
        }`}
      >
        <span
          className={`absolute top-0.5 left-0.5 w-4 h-4 rounded-full bg-white shadow-sm transition-transform ${
            checked ? 'translate-x-4' : 'translate-x-0'
          }`}
        />
      </button>
    </div>
  );
}

export default function BotPage(): React.ReactElement {
  const [running, setRunning] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [form, setForm] = useState<BotForm>({ keywords: '', location: '', limit: 20, autoSend: false });
  const [status, setStatus] = useState<BotStatus | null>(null);
  const socketRef = useRef<Socket | null>(null);
  const logsEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const socket: Socket = io('http://localhost:3001');
    socketRef.current = socket;

    socket.on('bot:log', (data: { message: string; step?: string }) => {
      setLogs((prev) => [...prev, { type: 'log', ...data, ts: new Date().toLocaleTimeString() }]);
    });
    socket.on('bot:lead', (lead: { nom: string; score?: number }) => {
      setLogs((prev) => [
        ...prev,
        { type: 'lead', message: `Lead ajouté: ${lead.nom} (${lead.score}/10)`, ts: new Date().toLocaleTimeString() },
      ]);
    });
    socket.on('bot:done', (data: { total: number }) => {
      setLogs((prev) => [
        ...prev,
        { type: 'done', message: `Terminé — ${data.total} leads sauvegardés`, ts: new Date().toLocaleTimeString() },
      ]);
      setRunning(false);
    });
    socket.on('bot:error', (data: { message: string }) => {
      setLogs((prev) => [
        ...prev,
        { type: 'error', message: `Erreur: ${data.message}`, ts: new Date().toLocaleTimeString() },
      ]);
      setRunning(false);
    });

    fetchStatus();
    return () => { socket.disconnect(); };
  }, []);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const fetchStatus = async (): Promise<void> => {
    try {
      const { data } = await api.get('/bot/status');
      setStatus(data);
    } catch {}
  };

  const startBot = async (): Promise<void> => {
    if (!form.keywords) return alert('Mots-clés requis');
    setLogs([]);
    setRunning(true);
    await api.post('/bot/start', form);
  };

  const stopBot = async (): Promise<void> => {
    await api.post('/bot/stop');
    setRunning(false);
    setLogs((prev) => [
      ...prev,
      { type: 'warn', message: 'Bot arrêté manuellement', ts: new Date().toLocaleTimeString() },
    ]);
  };

  const statusBadges: [string, number, string][] = status
    ? [
        ['En attente', status.waiting, 'text-zinc-400'],
        ['Actifs', status.active, 'text-emerald-400'],
        ['Terminés', status.completed, 'text-indigo-400'],
        ['Échoués', status.failed, 'text-red-400'],
      ]
    : [];

  return (
    <div className="p-6 h-full">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-base font-semibold text-zinc-100">Bot Engine</h1>
        {status && (
          <div className="flex items-center gap-1">
            {statusBadges.map(([label, val, color]) => (
              <div key={label} className="flex items-center gap-1.5 px-2.5 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md">
                <span className={`text-xs font-semibold tabular-nums ${color}`}>{val}</span>
                <span className="text-xs text-zinc-600">{label}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="flex gap-5 h-[calc(100vh-10rem)]">
        {/* Left: Config (40%) */}
        <div className="w-2/5 flex flex-col gap-4">
          {/* Search section */}
          <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
            <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-4">
              Paramètres de recherche
            </h2>
            <div className="space-y-3">
              <div>
                <label className="text-xs text-zinc-500 mb-1.5 block">
                  Mots-clés <span className="text-red-400">*</span>
                </label>
                <input
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2 text-xs text-zinc-200 placeholder-zinc-700 focus:outline-none focus:border-zinc-600 transition-colors"
                  placeholder="ex: CEO SaaS Paris"
                  value={form.keywords}
                  onChange={(e) => setForm({ ...form, keywords: e.target.value })}
                />
              </div>
              <div>
                <label className="text-xs text-zinc-500 mb-1.5 block">Localisation</label>
                <input
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2 text-xs text-zinc-200 placeholder-zinc-700 focus:outline-none focus:border-zinc-600 transition-colors"
                  placeholder="ex: France"
                  value={form.location}
                  onChange={(e) => setForm({ ...form, location: e.target.value })}
                />
              </div>
              <div>
                <label className="text-xs text-zinc-500 mb-1.5 block">Limite de leads</label>
                <input
                  type="number"
                  min={1}
                  max={500}
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2 text-xs text-zinc-200 focus:outline-none focus:border-zinc-600 transition-colors"
                  value={form.limit}
                  onChange={(e) => setForm({ ...form, limit: parseInt(e.target.value) })}
                />
              </div>
            </div>
          </div>

          {/* Options section */}
          <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
            <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-4">
              Options
            </h2>
            <Toggle
              checked={form.autoSend}
              onChange={(v) => setForm({ ...form, autoSend: v })}
              label="Auto-envoyer emails"
              description="Envoie automatiquement un email à chaque lead découvert"
            />
          </div>

          {/* Actions */}
          <div className="space-y-2.5">
            <button
              onClick={startBot}
              disabled={running}
              className="w-full flex items-center justify-center gap-2 py-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-zinc-800 disabled:text-zinc-600 disabled:cursor-not-allowed text-white text-sm font-medium rounded-xl transition-colors"
            >
              {running ? (
                <>
                  <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
                    <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" strokeDasharray="40" strokeDashoffset="10" />
                  </svg>
                  En cours...
                </>
              ) : (
                <>
                  <PlayIcon />
                  Démarrer le bot
                </>
              )}
            </button>
            <button
              onClick={stopBot}
              disabled={!running}
              className="w-full flex items-center justify-center gap-2 py-3 bg-zinc-900 border border-zinc-800 hover:bg-red-500/10 hover:border-red-500/30 hover:text-red-400 disabled:opacity-30 disabled:cursor-not-allowed text-zinc-400 text-sm font-medium rounded-xl transition-colors"
            >
              <StopIcon />
              Arrêter le bot
            </button>
          </div>
        </div>

        {/* Right: Terminal (60%) */}
        <div className="flex-1 flex flex-col bg-zinc-950 border border-zinc-800 rounded-xl overflow-hidden">
          {/* Terminal header */}
          <div className="flex items-center justify-between px-4 py-2.5 bg-zinc-900 border-b border-zinc-800">
            <div className="flex items-center gap-2">
              <div className="flex gap-1.5">
                <span className="w-3 h-3 rounded-full bg-zinc-700" />
                <span className="w-3 h-3 rounded-full bg-zinc-700" />
                <span className="w-3 h-3 rounded-full bg-zinc-700" />
              </div>
              <span className="text-xs text-zinc-600 ml-2 font-mono">bot.log</span>
            </div>
            <div className="flex items-center gap-2">
              {running && (
                <span className="flex items-center gap-1.5 text-xs text-emerald-400">
                  <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                  Running
                </span>
              )}
              <button
                onClick={() => setLogs([])}
                className="flex items-center gap-1 text-xs text-zinc-600 hover:text-zinc-400 transition-colors"
              >
                <ClearIcon />
                Vider
              </button>
            </div>
          </div>

          {/* Log content */}
          <div className="flex-1 overflow-y-auto p-4 font-mono text-xs leading-relaxed">
            {logs.length === 0 ? (
              <div className="flex items-center gap-2 text-zinc-700">
                <span className="text-zinc-800">$</span>
                <span>En attente de démarrage...</span>
                <span className="inline-block w-1.5 h-3.5 bg-zinc-700 animate-pulse ml-0.5" />
              </div>
            ) : (
              logs.map((log, i) => (
                <div key={i} className="flex gap-3 mb-0.5 hover:bg-zinc-900/40 rounded px-1 -mx-1 transition-colors">
                  <span className="text-zinc-700 flex-shrink-0 tabular-nums select-none">{log.ts}</span>
                  <span className={`flex-shrink-0 tabular-nums select-none ${LOG_COLORS[log.type] || 'text-zinc-500'}`}>
                    {LOG_PREFIX[log.type] || 'INFO'}
                  </span>
                  <span className={LOG_COLORS[log.type] || 'text-zinc-400'}>{log.message}</span>
                </div>
              ))
            )}
            <div ref={logsEndRef} />
          </div>
        </div>
      </div>
    </div>
  );
}
